  },
  btn: {
    padding: '4px 10px',
    borderRadius: 4,
    border: '1px solid #ccc',
    background: '#fff',
    cursor: 'pointer',
    fontSize: 12,
    color: '#333',
  },
  btnReset: {
    borderColor: '#ff5722',
    color: '#ff5722',
  },
  error: {
    padding: '6px 10px',
    background: '#ffebee',
    color: '#c62828',
    fontSize: 12,
    borderBottom: '1px solid #ef9a9a',
  },
  editorContainer: {
    flex: 1,
    overflow: 'hidden',
  },
  empty: {
    padding: 20,
    color: '#999',
    textAlign: 'center' as const,
  },
};

const darkStyles: Record<string, React.CSSProperties> = {
  container: {
    display: 'flex',
