import { chromium } from 'playwright';

const browser = await chromium.launch({ headless: true });
const context = await browser.newContext({ viewport: { width: 1920, height: 1080 } });
const page = await context.newPage();

// Collect console messages
const logs = [];
page.on('console', msg => logs.push(`[${msg.type()}] ${msg.text()}`));

// Navigate to correct story path
await page.goto('http://localhost:6006/?path=/story/sdui-voucherdemo--form', { waitUntil: 'networkidle', timeout: 30000 });
await page.waitForTimeout(4000);

await page.screenshot({ path: '.storybook/screenshots/editor-state-light.png', fullPage: false });
console.log('Captured light mode');

// Check editor content
const editorContent = await page.evaluate(() => {
  const cm = document.querySelector('.cm-content');
  return cm ? cm.textContent?.substring(0, 300) : 'NO CM FOUND';
});
console.log('Editor content:', editorContent);

// Check if SDUI JSON label is visible
const panelText = await page.evaluate(() => {
  const panel = document.querySelector('[id*="sdui-json-editor"]');
  return panel ? panel.textContent?.substring(0, 200) : 'PANEL NOT FOUND';
});
console.log('Panel:', panelText);

// Print relevant console messages
const relevant = logs.filter(l => l.includes('sdui') || l.includes('json') || l.includes('channel') || l.includes('error'));
console.log('Relevant logs:', relevant.slice(0, 10));

