import { chromium } from 'playwright';

const browser = await chromium.launch({ headless: true });
const context = await browser.newContext({ viewport: { width: 1920, height: 1080 } });
const page = await context.newPage();

// Navigate to an SDUI demo story
await page.goto('http://localhost:6006/?path=/story/sdui-demo--form', { waitUntil: 'networkidle', timeout: 30000 });
await page.waitForTimeout(3000);

// Full page screenshot
await page.screenshot({ path: '.storybook/screenshots/editor-current-light.png', fullPage: false });
console.log('Captured light mode');

// Now try dark mode - set Storybook to dark theme
await page.evaluate(() => {
  localStorage.setItem('sb-ui-theme', 'dark');
});
await page.goto('http://localhost:6006/?path=/story/sdui-demo--form', { waitUntil: 'networkidle', timeout: 30000 });
await page.waitForTimeout(3000);
await page.screenshot({ path: '.storybook/screenshots/editor-current-dark.png', fullPage: false });
console.log('Captured dark mode');

// Check the right panel specifically
const panel = await page.$('[id="panel-tab-content"]');
if (panel) {
  await panel.screenshot({ path: '.storybook/screenshots/editor-panel-only.png' });
  console.log('Captured panel only');
}

// Check if editor has content
const editorContent = await page.evaluate(() => {
  const cm = document.querySelector('.cm-content');
  return cm ? cm.textContent?.substring(0, 200) : 'NO CM FOUND';
});
console.log('Editor content:', editorContent);

// Check for any visible errors
const errors = await page.evaluate(() => {
  const errorEls = document.querySelectorAll('[class*="error"]');
  return Array.from(errorEls).map(e => e.textContent?.substring(0, 100));
});
console.log('Errors:', errors);

await browser.close();

