import { chromium } from 'playwright';

const browser = await chromium.launch({ headless: true });
const context = await browser.newContext({ viewport: { width: 1920, height: 1080 } });
const page = await context.newPage();

// Test 1: Light mode - Form story
await page.goto('http://localhost:6006/?path=/story/sdui-voucherdemo--form', { waitUntil: 'networkidle', timeout: 30000 });
await page.waitForTimeout(4000);
await page.screenshot({ path: '.storybook/screenshots/editor-p0-light.png' });
console.log('1. Light mode captured');

// Test 2: Switch stories - does editor update?
await page.goto('http://localhost:6006/?path=/story/sdui-voucherdemo--summary', { waitUntil: 'networkidle', timeout: 30000 });
await page.waitForTimeout(4000);
await page.screenshot({ path: '.storybook/screenshots/editor-p0-summary.png' });
const summaryContent = await page.evaluate(() => {
  const cm = document.querySelector('.cm-content');
  return cm ? cm.textContent?.substring(0, 100) : 'EMPTY';
});
console.log('2. Summary content:', summaryContent);

// Test 3: Dark mode
await page.evaluate(() => localStorage.setItem('sb-ui-theme', 'dark'));
await page.goto('http://localhost:6006/?path=/story/sdui-voucherdemo--form', { waitUntil: 'networkidle', timeout: 30000 });
await page.waitForTimeout(4000);
await page.screenshot({ path: '.storybook/screenshots/editor-p0-dark.png' });
console.log('3. Dark mode captured');

// Test 4: Screenshot just the right panel in dark mode
const rightPanel = await page.$('.css-sqdry3');
if (rightPanel) {
  await rightPanel.screenshot({ path: '.storybook/screenshots/editor-p0-dark-panel.png' });
} else {
  // Try to find the panel area by looking for SDUI JSON text
  const allPanels = await page.$$('div');
  console.log('4. Could not find panel with specific selector');
}

// Test 5: Check if the panel reacts to dark mode properly - inspect colors
const panelBg = await page.evaluate(() => {
  // Find the div containing "SDUI JSON" text
  const allElements = document.querySelectorAll('*');
  for (const el of allElements) {
    if (el.textContent?.includes('SDUI JSON') && el.children.length < 5) {
      const parent = el.closest('div');
      if (parent) {
        const style = window.getComputedStyle(parent);
        return {
          bg: style.backgroundColor,
          color: style.color,
          found: true,
        };
      }
    }
  }
  return { found: false };
});
console.log('5. Panel bg info:', panelBg);

// Restore light mode
await page.evaluate(() => localStorage.removeItem('sb-ui-theme'));

await browser.close();

