import { chromium } from 'playwright';

const browser = await chromium.launch({ headless: true });
const context = await browser.newContext({ viewport: { width: 1920, height: 1080 } });
const page = await context.newPage();

// Go to form story
await page.goto('http://localhost:6006/?path=/story/sdui-voucherdemo--form', { waitUntil: 'networkidle', timeout: 30000 });
await page.waitForTimeout(4000);

// Find the CodeMirror editor and type JSON5 content
const cmEditor = await page.$('.cm-content');
if (cmEditor) {
  // Select all and replace
  await cmEditor.click();
  await page.keyboard.down('Meta');
  await page.keyboard.press('a');
  await page.keyboard.up('Meta');
  await page.waitForTimeout(200);

  // Type JSON5 with unquoted keys
  const json5Input = `{
  id: "test_json5",
  body: [
    {
      type: "heading",
      props: {
        text: "Hello JSON5"
      }
    }
  ]
}`;
  await page.keyboard.type(json5Input, { delay: 5 });
  await page.waitForTimeout(2000);

  // Screenshot showing JSON5 in editor
  await page.screenshot({ path: '.storybook/screenshots/editor-p0-json5.png' });
  console.log('JSON5 test captured');

  // Check if there are lint markers (error indicators)
  const lintMarkers = await page.$$('.cm-lint-marker-error');
  console.log('Lint error markers:', lintMarkers.length);

  const lintWarnings = await page.$$('.cm-lint-marker-warning');
  console.log('Lint warning markers:', lintWarnings.length);

  // Check the error bar
  const errorBar = await page.evaluate(() => {
    const el = document.querySelector('[style*="ffebee"], [style*="4a1e1e"]');
    return el ? el.textContent : 'NO ERROR BAR';
  });
  console.log('Error bar:', errorBar);

  // Check for wavy underlines (syntax errors from json() parser)
  const lintRanges = await page.$$('.cm-lintRange-error');
  console.log('Error ranges in text:', lintRanges.length);
}

await browser.close();

