    background: '#fafafa',
  },
  label: {
    fontWeight: 600,
    fontSize: 13,
    color: '#333',
  },
  badge: {
    display: 'inline-block',
    marginLeft: 6,
    padding: '1px 6px',
    borderRadius: 4,
    background: '#ff9800',
    color: '#fff',
    fontSize: 10,
    fontWeight: 700,
  },
  actions: {
    display: 'flex',
    gap: 6,
