import { chromium } from 'playwright';

const browser = await chromium.launch({ headless: true });
const context = await browser.newContext({ viewport: { width: 1920, height: 1080 } });
const page = await context.newPage();

// Test 1: Light mode — editor loads with initial JSON
await page.goto('http://localhost:6006/?path=/story/sdui-voucherdemo--form', { waitUntil: 'networkidle', timeout: 30000 });
await page.waitForTimeout(5000);
await page.screenshot({ path: '.storybook/screenshots/editor-fix-light.png' });

const content1 = await page.evaluate(() => {
  const cm = document.querySelector('.cm-content');
  return cm ? cm.textContent?.substring(0, 80) : 'EMPTY';
});
console.log('1. Light mode loaded:', content1);

// Test 2: Dark mode
await page.evaluate(() => localStorage.setItem('sb-ui-theme', 'dark'));
await page.goto('http://localhost:6006/?path=/story/sdui-voucherdemo--form', { waitUntil: 'networkidle', timeout: 30000 });
await page.waitForTimeout(5000);
await page.screenshot({ path: '.storybook/screenshots/editor-fix-dark.png' });
console.log('2. Dark mode captured');

// Test 3: Type JSON5 with unquoted keys
const cmEditor = await page.$('.cm-content');
if (cmEditor) {
  await cmEditor.click();
  await page.keyboard.down('Meta');
  await page.keyboard.press('a');
  await page.keyboard.up('Meta');
  await page.waitForTimeout(100);
  await page.keyboard.press('Backspace');
  await page.waitForTimeout(200);

  // Paste JSON5 content
  const json5 = `{
  id: "test_json5",
  body: [
    {
      type: "heading",
      props: {
        text: "Hello JSON5 — unquoted keys work!"
      }
    }
  ]
}`;
  await page.evaluate((text) => navigator.clipboard.writeText(text), json5);
  await page.keyboard.down('Meta');
  await page.keyboard.press('v');
  await page.keyboard.up('Meta');
  await page.waitForTimeout(2000);

  await page.screenshot({ path: '.storybook/screenshots/editor-fix-json5.png' });

  // Check for error bar
  const errorBar = await page.evaluate(() => {
    const els = document.querySelectorAll('div');
    for (const el of els) {
      const text = el.textContent || '';
      if (text.includes('⚠') && el.children.length === 0 && text.length < 200) {
        return text;
      }
    }
    return 'NO ERROR';
  });
  console.log('3. JSON5 error bar:', errorBar);

  const lintErrors = await page.$$('.cm-lint-marker-error');
  console.log('3. Lint error markers:', lintErrors.length);

  // Check if preview updated
  const previewText = await page.evaluate(() => {
    const iframe = document.querySelector('#storybook-preview-iframe');
    if (iframe) {
      return (iframe).contentDocument?.body?.textContent?.substring(0, 200) || 'IFRAME EMPTY';
    }
    return 'NO IFRAME';
  });
  console.log('3. Preview:', previewText?.substring(0, 100));
}

// Test 4: Navigate to a non-SDUI story
await page.goto('http://localhost:6006/?path=/story/screens-points--loaded', { waitUntil: 'networkidle', timeout: 30000 });
await page.waitForTimeout(4000);
await page.screenshot({ path: '.storybook/screenshots/editor-fix-non-sdui.png' });

const waitingMsg = await page.evaluate(() => {
  const els = document.querySelectorAll('div');
  for (const el of els) {
    if (el.textContent?.includes('Waiting for story')) return el.textContent;
  }
  return 'NOT FOUND';
});
console.log('4. Non-SDUI story panel:', waitingMsg);

// Cleanup
await page.evaluate(() => localStorage.removeItem('sb-ui-theme'));
await browser.close();

